1	import { log } from "cc";
2	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define from "../Game_Define";
5	import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
6	import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
7	
8	export class MatchingPatchUpState extends BaseState
9	{
10	    private m_gameView: GameView = null;
11	
12	    constructor( gameView: GameView )
13	    {
14	        super();
15	        this.m_gameView = gameView;
16	    }
17	
18	    public async OnEnter()
19	    {
20	        log( "game state MATCHING_PATCH_UP" );
21	
22	        const curRoundInfo = this.m_gameView.RoundInfo;
23	        const curPlateIndex = this.m_gameView.CurPlateIndex;
24	
25	        // 回歸守衛：本盤消除後（Explode②ADD + WantedPoster④SET 已全部完成），
26	        // 被消除位置的乘倍底板 index 應等於 Server 的 BasePlateIndex。不一致只 log，不影響流程。
27	        const playedPlate = curRoundInfo.PlateQueue[ curPlateIndex ];
28	        if ( playedPlate?.BasePlateIndex && playedPlate?.EliminatePos )
29	        {
30	            eventManager.Dispatch(
31	                MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER,
32	                playedPlate.BasePlateIndex,
33	                playedPlate.EliminatePos
34	            );
35	        }
36	
37	        if (curPlateIndex >= curRoundInfo.PlateQueue.length-1)
38	        {
39	            this.m_gameView.CurPlateIndex++;
40	            //統一由COUNT_MULT切流程
41	            stateManager.NextState( Game_Define.GameState.COUNT_MULT);
